firmware_template.source:
#include "watchdog.h"
#include <esp_task_wdt.h>
void watchdog_setup(uint32_t ms){esp_task_wdt_config_t cfg={.timeout_ms=ms,.idle_core_mask=(1<<0)|(1<<1),.trigger_panic=true};esp_task_wdt_init(&cfg);esp_task_wdt_add(NULL);Serial.printf("[wdt] OK %ldms\n",(long)ms);}
void watchdog_feed(){esp_task_wdt_reset();}
void watchdog_disable(){esp_task_wdt_delete(NULL);}
